-- Estrutura fiscal · Plano de Contas + Centros de Custo
-- Fonte: PlanoDeContas.rtf + CentrosDeCusto.rtf (Marcos · 2026-05-21)
-- Idempotente · pode rodar varias vezes sem efeito colateral

-- ============================================================
-- 1. PLANO DE CONTAS (hierarquico ate 5 niveis)
-- ============================================================
CREATE TABLE IF NOT EXISTS fin_plano_contas (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  codigo text NOT NULL UNIQUE,
  codigo_pai text REFERENCES fin_plano_contas(codigo) ON DELETE RESTRICT,
  nome text NOT NULL,
  tipo text NOT NULL CHECK (tipo IN ('ativo', 'passivo', 'receita', 'despesa')),
  natureza text CHECK (natureza IN ('ordinaria', 'extraordinaria', 'patrimonial', 'financeira', NULL)),
  nivel int NOT NULL CHECK (nivel BETWEEN 1 AND 5),
  aceita_lancamento boolean NOT NULL DEFAULT false,
  ativo boolean NOT NULL DEFAULT true,
  ordem int DEFAULT 0,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS fin_plano_contas_pai_idx ON fin_plano_contas(codigo_pai);
CREATE INDEX IF NOT EXISTS fin_plano_contas_tipo_idx ON fin_plano_contas(tipo) WHERE ativo;
CREATE INDEX IF NOT EXISTS fin_plano_contas_aceita_idx ON fin_plano_contas(aceita_lancamento) WHERE ativo;

-- ============================================================
-- 2. CENTROS DE CUSTO (hierarquico ate 5 niveis · multi-campus)
-- ============================================================
CREATE TABLE IF NOT EXISTS fin_centros_custo (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  codigo text NOT NULL UNIQUE,
  codigo_pai text REFERENCES fin_centros_custo(codigo) ON DELETE RESTRICT,
  nome text NOT NULL,
  campus text,
  area_slug text,
  nivel int NOT NULL CHECK (nivel BETWEEN 1 AND 5),
  aceita_lancamento boolean NOT NULL DEFAULT false,
  ativo boolean NOT NULL DEFAULT true,
  ordem int DEFAULT 0,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS fin_centros_custo_pai_idx ON fin_centros_custo(codigo_pai);
CREATE INDEX IF NOT EXISTS fin_centros_custo_campus_idx ON fin_centros_custo(campus) WHERE ativo;
CREATE INDEX IF NOT EXISTS fin_centros_custo_area_idx ON fin_centros_custo(area_slug) WHERE area_slug IS NOT NULL;

-- ============================================================
-- 3. SEED · PLANO DE CONTAS (110 contas do RTF)
-- ============================================================
-- 1 ATIVO
ON CONFLICT (codigo) DO NOTHING;

-- 2 PASSIVO
ON CONFLICT (codigo) DO NOTHING;

-- 3 RECEITAS
ON CONFLICT (codigo) DO NOTHING;

-- 4 DESPESAS
ON CONFLICT (codigo) DO NOTHING;

-- ============================================================
-- 4. SEED · CENTROS DE CUSTO (51 itens do RTF)
-- ============================================================
ON CONFLICT (codigo) DO NOTHING;

COMMIT;
